import { DEFAULTS } from '../defaults.js';
import { useTooltipSnapshot } from '../selectors.js';
import { isTooltipDataEmpty } from '../utils.js';

/** @internal */
export const useDefaultConfig = () => {
  const data = useTooltipSnapshot().data;

  if (isTooltipDataEmpty(data)) {
    return null;
  }

  return DEFAULTS[data.geometry];
};
